class UserValidator:
    @staticmethod
    def validate_email(email):
        if "@" not in email:
            raise ValueError("invalid email")
        local, _, domain = email.partition("@")
        if not local or "." not in domain:
            raise ValueError("invalid email domain")
        return True

    @staticmethod
    def validate_password(password):
        if len(password) < 8:
            raise ValueError("password too short")
        if not any(c.isdigit() for c in password):
            raise ValueError("password needs a digit")
        return True

class UserRepository:
    def __init__(self, db_connection):
        self.db = db_connection

    def get_user_by_id(self, user_id):
        return self.db.execute("SELECT * FROM users WHERE id = ?", (user_id,)).fetchone()

    def get_user_by_email(self, email):
        return self.db.execute("SELECT * FROM users WHERE email = ?", (email,)).fetchone()

    def insert_user(self, email, password):
        self.db.execute("INSERT INTO users (email, password) VALUES (?, ?)", (email, password))
        self.db.commit()

class UserService:
    def __init__(self, db_connection):
        self.repository = UserRepository(db_connection)
        self.validator = UserValidator()

    def create_user(self, email, password):
        self.validator.validate_email(email)
        self.validator.validate_password(password)
        self.repository.insert_user(email, password)
